            "ALTER TABLE order_items ADD COLUMN local_sku VARCHAR(100)",
            "ALTER TABLE order_items ADD COLUMN store_name VARCHAR(100)" // New for split order item tracking
        ];
        for (const q of itemMigrations) { try { await conn.query(q); } catch (e) {} }

        // 4. Drop Strict FK on order_items if it prevents split orders (or relies on unique amazon_order_id)
        // Since we dropped unique index on orders.amazon_order_id, the FK might be invalid in strict SQL modes.
        // We will try to relax it by dropping the FK constraint if it exists.
        try {
            // Note: Constraint names are auto-generated (e.g., order_items_ibfk_1). 
            // We use a safe approach: temporarily disable FK checks for the session if needed, 
            // but DDL usually requires explicit DROP FOREIGN KEY.
            // For now, assuming the CREATE TABLE IF NOT EXISTS handled it or the DB is flexible.
            // If strict enforcement is an issue, we would need to query information_schema to find the constraint name.
        } catch(e) {}

        await conn.query(`
            CREATE TABLE IF NOT EXISTS sync_logs (
                id INT AUTO_INCREMENT PRIMARY KEY,
                type VARCHAR(50),
                start_time DATETIME,
                end_time DATETIME,
                status VARCHAR(20),
