                                    }} className="text-left px-4 py-1.5 hover:text-blue-600 hover:bg-gray-50 transition-colors">{p}</button>
                                ))}
                            </div>
                        )}

                        <div className="p-4 bg-white flex gap-8">
                            {renderCalendar(0, 0)}
