const formatDate = (date: Date) => {
  const y = date.getFullYear();
  const m = String(date.getMonth() + 1).padStart(2, '0');
  const d = String(date.getDate()).padStart(2, '0');
  return `${y}-${m}-${d}`;
};

const formatDateTime = (date: Date) => {
    return date.toISOString().slice(0, 19).replace('T', ' ');
};

// --- CORE LOGIC: Los Angeles Date Anchor ---
// Returns a date object based on 'America/Los_Angeles' time with offset days.
// This ensures "Today" and "Yesterday" align with Amazon's PST/PDT business day.
const getLADate = (offsetDays = 0) => {
    const now = new Date();
    const formatter = new Intl.DateTimeFormat('en-US', {
        timeZone: 'America/Los_Angeles',
        year: 'numeric',
        month: 'numeric',
        day: 'numeric'
    });
    const parts = formatter.formatToParts(now);
    const year = parseInt(parts.find(p => p.type === 'year')?.value || '0');
    const month = parseInt(parts.find(p => p.type === 'month')?.value || '0') - 1; // JS months are 0-11
    const day = parseInt(parts.find(p => p.type === 'day')?.value || '0');

    // Construct local Date object representing the LA date at 00:00:00
    // We use local constructor so 'formatDate' (which uses local getFullYear etc) works predictably
    const d = new Date(year, month, day);
    d.setDate(d.getDate() + offsetDays);
    d.setHours(0,0,0,0);
    return d;
};

