                          {(pickerMode === 'week' || offsetMonth === 0) && <ChevronLeft size={16} className="cursor-pointer hover:text-gray-600" onClick={(e) => { e.stopPropagation(); setPickerViewDate(new Date(year, month-1, 1)); }} />}
                      </div>
