      { title: '销售额', value: summary?.amount?.value || 0, yesterday: summary?.amount?.yesterday || 0, lastWeek: summary?.amount?.lastWeek || 0, prefix: 'US$', decimals: 2 },
      { title: '订单量', value: summary?.orders?.value || 0, yesterday: summary?.orders?.yesterday || 0, lastWeek: summary?.orders?.lastWeek || 0 },
      { title: '商品均价', value: summary?.avgPrice?.value || 0, yesterday: summary?.avgPrice?.yesterday || 0, lastWeek: summary?.avgPrice?.lastWeek || 0, prefix: 'US$', decimals: 2 },
      { title: '取消订单数', value: summary?.cancelled?.value || 0, yesterday: summary?.cancelled?.yesterday || 0, lastWeek: summary?.cancelled?.lastWeek || 0 }
  ];

  return (
